// src/pricing/discount.ts
import { Money } from "../money";

export interface DiscountRule {
  code: string;
  percentOff: number;
  minSubtotal: number;
  expiresAt: Date;
}

export function applyDiscount(subtotal: Money, rule: DiscountRule): Money {
  if (subtotal.amount < rule.minSubtotal) {
    return subtotal;
  }
  const reduction = subtotal.amount * (rule.percentOff / 100);
  return subtotal.minus(reduction);
}

export function isExpired(rule: DiscountRule, now: Date): boolean {
  return rule.expiresAt.getTime() < now.getTime();
}
